SELECT * FROM file_metadata

    (file_type IS NULL OR (file_type NOT LIKE '%pdf%' AND file_type NOT LIKE '%word%' AND file_type NOT LIKE '%msword%'
    AND file_type NOT LIKE '%csv%' AND file_type NOT LIKE '%spreadsheet%' AND file_type NOT LIKE '%excel%'
    AND file_type NOT LIKE '%powerpoint%' AND file_type NOT LIKE '%presentation%'))

        AND create_by = #{createBy}




        ORDER BY ${orderBy}

            ASC
            DESC


    ORDER BY create_time DESC

LIMIT #{offset}, #{size}

SELECT * FROM file_metadata WHERE (file_name LIKE CONCAT('%', #{keyword}, '%') OR original_file_name LIKE CONCAT('%', #{keyword}, '%')) AND (file_type IS NULL OR (file_type NOT LIKE '%pdf%' AND file_type NOT LIKE '%word%' AND file_type NOT LIKE '%msword%' AND file_type NOT LIKE '%csv%' AND file_type NOT LIKE '%spreadsheet%' AND file_type NOT LIKE '%excel%' AND file_type NOT LIKE '%powerpoint%' AND file_type NOT LIKE '%presentation%'))
AND create_by = #{createBy}
ORDER BY create_time DESC LIMIT #{offset}, #{size}

